"use client"

import * as React from "react"

function legacyCopyToClipboard(value: string) {
  const textArea = document.createElement("textarea")
  textArea.value = value
  textArea.setAttribute("readonly", "")
  textArea.style.position = "fixed"
  textArea.style.opacity = "0"
  textArea.style.pointerEvents = "none"

  document.body.appendChild(textArea)
  textArea.focus()
  textArea.select()
  textArea.setSelectionRange(0, value.length)

  let hasCopied = false
  try {
    hasCopied = document.execCommand("copy")
  } catch {
    hasCopied = false
  }

  document.body.removeChild(textArea)
  return hasCopied
}

export function useCopyToClipboard({
  timeout = 2000,
  onCopy,
}: {
  timeout?: number
  onCopy?: () => void
} = {}) {
  const [isCopied, setIsCopied] = React.useState(false)

  const copyToClipboard = async (value: string) => {
    if (typeof window === "undefined") {
      return false
    }

    if (!value) {
      return false
    }

    let hasCopied = false

    if (navigator.clipboard?.writeText) {
      try {
        await navigator.clipboard.writeText(value)
        hasCopied = true
      } catch {
        hasCopied = legacyCopyToClipboard(value)
      }
    } else {
      hasCopied = legacyCopyToClipboard(value)
    }

    if (!hasCopied) {
      return false
    }

    setIsCopied(true)

    if (onCopy) {
      onCopy()
    }

    if (timeout !== 0) {
      setTimeout(() => {
        setIsCopied(false)
      }, timeout)
    }

    return true
  }

  return { isCopied, copyToClipboard }
}

import type { WorkerRequestHandler } from '../../server/lib/types'
import type { NodeRequestHandler } from '../../server/next-server'
import { withRequest, type TestRequestReader } from './context'
import { interceptFetch } from './fetch'
import { interceptHttpGet } from './httpget'
import type { IncomingMessage } from 'http'

const reader: TestRequestReader<IncomingMessage> = {
  url(req) {
    return req.url ?? ''
  },
  header(req, name) {
    const h = req.headers[name]
    if (h === undefined || h === null) {
      return null
    }
    if (typeof h === 'string') {
      return h
    }
    return h[0] ?? null
  },
}

export function interceptTestApis(): () => void {
  const originalFetch = global.fetch
  const restoreFetch = interceptFetch(originalFetch)
  const restoreHttpGet = interceptHttpGet(originalFetch)

  // Cleanup.
  return () => {
    restoreFetch()
    restoreHttpGet()
  }
}

export function wrapRequestHandlerWorker(
  handler: WorkerRequestHandler
): WorkerRequestHandler {
  return (req, res) => withRequest(req, reader, () => handler(req, res))
}

export function wrapRequestHandlerNode(
  handler: NodeRequestHandler
): NodeRequestHandler {
  return (req, res, parsedUrl) =>
    withRequest(req, reader, () => handler(req, res, parsedUrl))
}

import {
  extractInfoFromServerReferenceId,
  type ServerReferenceInfo,
} from '../shared/lib/server-reference-info'

// Only contains the properties we're interested in.
export interface ServerReference {
  $$typeof: Symbol
  $$id: string
}

export type ServerFunction = ServerReference &
  ((...args: unknown[]) => Promise<unknown>)

export function isServerReference<T>(
  value: T & Partial<ServerReference>
): value is T & ServerFunction {
  return value.$$typeof === Symbol.for('react.server.reference')
}

export function isUseCacheFunction<T>(
  value: T & Partial<ServerReference>
): value is T & ServerFunction {
  if (!isServerReference(value)) {
    return false
  }

  const { type } = extractInfoFromServerReferenceId(value.$$id)

  return type === 'use-cache'
}

export function getUseCacheFunctionInfo<T>(
  value: T & Partial<ServerReference>
): ServerReferenceInfo | null {
  if (!isServerReference(value)) {
    return null
  }

  const info = extractInfoFromServerReferenceId(value.$$id)

  return info.type === 'use-cache' ? info : null
}

export function isClientReference(mod: any): boolean {
  const defaultExport = mod?.default || mod
  return defaultExport?.$$typeof === Symbol.for('react.client.reference')
}

"use client"

import {
  createContext,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react"

const DEFAULT_THEME = "default"

type ThemeContextType = {
  activeTheme: string
  setActiveTheme: (theme: string) => void
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined)

export function ActiveThemeProvider({
  children,
  initialTheme,
}: {
  children: ReactNode
  initialTheme?: string
}) {
  const [activeTheme, setActiveTheme] = useState<string>(
    () => initialTheme || DEFAULT_THEME
  )

  useEffect(() => {
    Array.from(document.body.classList)
      .filter((className) => className.startsWith("theme-"))
      .forEach((className) => {
        document.body.classList.remove(className)
      })
    document.body.classList.add(`theme-${activeTheme}`)
    if (activeTheme.endsWith("-scaled")) {
      document.body.classList.add("theme-scaled")
    }
  }, [activeTheme])

  return (
    <ThemeContext.Provider value={{ activeTheme, setActiveTheme }}>
      {children}
    </ThemeContext.Provider>
  )
}

export function useThemeConfig() {
  const context = useContext(ThemeContext)
  if (context === undefined) {
    throw new Error("useThemeConfig must be used within an ActiveThemeProvider")
  }
  return context
}

