import type { AcceptedLanguages } from '@payloadcms/translations'
import type { ReadonlyRequestCookies } from 'next/dist/server/web/spec-extension/adapters/request-cookies.js'

import { extractHeaderLanguage } from '@payloadcms/translations'

import type { SanitizedConfig } from '../config/types.js'

type GetRequestLanguageArgs = {
  config: SanitizedConfig
  cookies: Map<string, string> | ReadonlyRequestCookies
  defaultLanguage?: AcceptedLanguages
  headers: Request['headers']
}

export const getRequestLanguage = ({
  config,
  cookies,
  headers,
}: GetRequestLanguageArgs): AcceptedLanguages => {
  const supportedLanguageKeys = Object.keys(config.i18n.supportedLanguages) as AcceptedLanguages[]
  const langCookie = cookies.get(`${config.cookiePrefix || 'payload'}-lng`)

  const languageFromCookie: AcceptedLanguages = (
    typeof langCookie === 'string' ? langCookie : langCookie?.value
  ) as AcceptedLanguages

  if (languageFromCookie && supportedLanguageKeys.includes(languageFromCookie)) {
    return languageFromCookie
  }

  const languageFromHeader = headers.get('Accept-Language')
    ? extractHeaderLanguage(headers.get('Accept-Language')!)
    : undefined

  if (languageFromHeader && supportedLanguageKeys.includes(languageFromHeader)) {
    return languageFromHeader
  }

  return config.i18n.fallbackLanguage
}

import type {NextRequest, NextResponse} from 'next/server.js';
import type {Locale} from 'use-intl';
import type {
  InitializedLocaleCookieConfig,
  ResolvedRoutingConfig
} from '../routing/config.js';
import type {
  DomainConfig,
  DomainsConfig,
  LocalePrefixMode,
  Locales,
  Pathnames
} from '../routing/types.js';
import {getAcceptLanguageLocale} from './resolveLocale.js';

export default function syncCookie<
  AppLocales extends Locales,
  AppLocalePrefixMode extends LocalePrefixMode,
  AppPathnames extends Pathnames<AppLocales> | undefined,
  AppDomains extends DomainsConfig<AppLocales> | undefined
>(
  request: NextRequest,
  response: NextResponse,
  locale: Locale,
  routing: Pick<
    ResolvedRoutingConfig<
      AppLocales,
      AppLocalePrefixMode,
      AppPathnames,
      AppDomains
    >,
    'locales' | 'defaultLocale'
  > & {
    localeCookie: InitializedLocaleCookieConfig;
  },
  domain?: DomainConfig<AppLocales>
) {
  if (!routing.localeCookie) return;

  const {name, ...rest} = routing.localeCookie;
  const hasLocaleCookie = request.cookies.has(name);
  const hasOutdatedCookie =
    hasLocaleCookie && request.cookies.get(name)?.value !== locale;

  if (hasOutdatedCookie) {
    response.cookies.set(name, locale, {
      path: request.nextUrl.basePath || undefined,
      ...rest
    });
  } else if (!hasLocaleCookie) {
    const acceptLanguageLocale = getAcceptLanguageLocale(
      request.headers,
      domain?.locales || routing.locales,
      routing.defaultLocale
    );
    if (acceptLanguageLocale !== locale) {
      response.cookies.set(name, locale, {
        path: request.nextUrl.basePath || undefined,
        ...rest
      });
    }
  }
}

import {cache} from 'react';
import type {
  Locale,
  Messages,
  NamespaceKeys,
  NestedKeyOf,
  createTranslator
} from 'use-intl/core';
import getConfig from './getConfig.js';
import getServerTranslator from './getServerTranslator.js';

// Maintainer note: `getTranslations` has two different call signatures.
// We need to define these with function overloads, otherwise TypeScript
// messes up the return type.

// Call signature 1: `getTranslations(namespace)`
function getTranslations<
  NestedKey extends NamespaceKeys<Messages, NestedKeyOf<Messages>> = never
>(
  namespace?: NestedKey
): Promise<ReturnType<typeof createTranslator<Messages, NestedKey>>>;
// Call signature 2: `getTranslations({locale, namespace})`
function getTranslations<
  NestedKey extends NamespaceKeys<Messages, NestedKeyOf<Messages>> = never
>(opts?: {
  locale: Locale;
  namespace?: NestedKey;
}): Promise<ReturnType<typeof createTranslator<Messages, NestedKey>>>;
// Implementation
async function getTranslations<
  NestedKey extends NamespaceKeys<Messages, NestedKeyOf<Messages>> = never
>(namespaceOrOpts?: NestedKey | {locale: Locale; namespace?: NestedKey}) {
  let namespace: NestedKey | undefined;
  let locale: Locale | undefined;

  if (typeof namespaceOrOpts === 'string') {
    namespace = namespaceOrOpts;
  } else if (namespaceOrOpts) {
    locale = namespaceOrOpts.locale;
    namespace = namespaceOrOpts.namespace;
  }

  const config = await getConfig(locale);
  return getServerTranslator(config, namespace);
}

export default cache(getTranslations);

import type {RoutingConfig} from './config.js';
import type {
  DomainsConfig,
  LocalePrefixMode,
  Locales,
  Pathnames
} from './types.js';

export default function defineRouting<
  const AppLocales extends Locales,
  const AppLocalePrefixMode extends LocalePrefixMode = 'always',
  const AppPathnames extends Pathnames<AppLocales> = never,
  const AppDomains extends DomainsConfig<AppLocales> = never
>(
  config: RoutingConfig<
    AppLocales,
    AppLocalePrefixMode,
    AppPathnames,
    AppDomains
  >
) {
  if (process.env.NODE_ENV !== 'production' && config.domains) {
    validateUniqueLocalesPerDomain(config.domains);
  }
  return config;
}

function validateUniqueLocalesPerDomain<
  AppLocales extends Locales,
  AppDomains extends DomainsConfig<AppLocales>
>(domains: AppDomains) {
  const domainsByLocale = new Map<string, Set<string>>();

  for (const {domain, locales} of domains) {
    for (const locale of locales) {
      const localeDomains = domainsByLocale.get(locale) || new Set<string>();
      localeDomains.add(domain);
      domainsByLocale.set(locale, localeDomains);
    }
  }

  const duplicateLocaleMessages = Array.from(domainsByLocale.entries())
    .filter(([, localeDomains]) => localeDomains.size > 1)
    .map(
      ([locale, localeDomains]) =>
        `- "${locale}" is used by: ${Array.from(localeDomains).join(', ')}`
    );

  if (duplicateLocaleMessages.length > 0) {
    console.warn(
      'Locales are expected to be unique per domain, but found overlap:\n' +
        duplicateLocaleMessages.join('\n') +
        '\nPlease see https://next-intl.dev/docs/routing/configuration#domains'
    );
  }
}

